class Solution {
    public int addMinimum(String word) {
        int count = 0;
        for (char c : word.toCharArray()) {
            if (c == 'a') {
                count++;
            } else if (c == 'b') {
                count += 2;
            } else {
                count += 3;
            }
        }
        return count - word.length();
    }
}
```

